      "path": "src/modules/tasks/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const projectsService = require('../projects/service');

function createTask(projectId) {
  const project = projectsService.getProjectById(projectId);
  if (!project) return null;
  const task = { id: randomUUID(), status: 'todo', comments: [] };
  project.tasks.push(task);
  return task;
}

function getTasksByProjectId(projectId) {
  const project = projectsService.getProjectById(projectId);
  return project ? project.tasks : [];
}

function updateTaskStatus(taskId, status) {
  for (const projectId in projectsService.getAllProjects()) {
    const project = projectsService.getProjectById(projectId);
    const taskIndex = project.tasks.findIndex(task => task.id === taskId);
    if (taskIndex !== -1) {
      project.tasks[taskIndex].status = status;
      return project.tasks[taskIndex];
    }
  }
  return null;
}

module.exports = {
  createTask,
  getTasksByProjectId,
  updateTaskStatus,
};
